import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isRegisterMode, setIsRegisterMode] = useState(false);
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [userRole, setUserRole] = useState('');
  const [nuevoRol, setNuevoRol] = useState('vendedor'); 

  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  const abortControllerRef = useRef(null);

  // --- LÓGICA (Mantenida de tu código original) ---
  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error(error); } finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(() => cargarDatos(), 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  const ejecutarBusqueda = async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { signal: abortControllerRef.current.signal });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  };

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [cargarDatos]); 

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) { setIsLoggedIn(true); setUserRole(res.data.rol); }
    } catch (e) { alert("Error de login"); }
  };

  const guardarProducto = async () => {
    const data = { nombre: nuevoProd.nombre, categoria: "General", stock: Number(nuevoProd.stock), precio_venta: Number(nuevoProd.precio_venta) };
    if (editMode) { await axios.put(`http://localhost:5000/api/productos/${selectedId}`, data); }
    else { await axios.post('http://localhost:5000/api/productos', data); }
    setShowForm(false); setEditMode(false); cargarDatos();
  };

  // --- INTERFAZ TIPO IMAGEN 2 (LOGIN DARK) ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center font-sans">
        <div className="bg-[#2d333b] p-10 rounded-[30px] shadow-2xl w-full max-w-md border border-gray-700">
          <div className="text-center mb-8">
            <h2 className="text-3xl font-bold text-white mb-2">{isRegisterMode ? 'Registro' : 'Login'}</h2>
            <div className="w-12 h-1 bg-[#00c984] mx-auto rounded-full"></div>
          </div>

          <div className="space-y-5">
            <div className="relative">
              <i className="fas fa-user absolute left-4 top-4 text-[#00c984]"></i>
              <input 
                className="w-full bg-[#444c56] text-white pl-12 pr-4 py-3 rounded-xl outline-none focus:ring-2 focus:ring-[#00c984] transition"
                placeholder="Nombre" 
                onChange={e => setUsuario(e.target.value)} 
              />
            </div>
            {isRegisterMode && (
                <div className="relative">
                    <i className="fas fa-envelope absolute left-4 top-4 text-[#00c984]"></i>
                    <input className="w-full bg-[#444c56] text-white pl-12 pr-4 py-3 rounded-xl outline-none focus:ring-2 focus:ring-[#00c984]" placeholder="Correo" />
                </div>
            )}
            <div className="relative">
              <i className="fas fa-lock absolute left-4 top-4 text-[#00c984]"></i>
              <input 
                type="password" 
                className="w-full bg-[#444c56] text-white pl-12 pr-4 py-3 rounded-xl outline-none focus:ring-2 focus:ring-[#00c984] transition"
                placeholder="Contraseña" 
                onChange={e => setPassword(e.target.value)} 
              />
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                className="flex-1 bg-[#00c984] text-white font-bold py-3 rounded-xl hover:bg-[#00a86b] transition active:scale-95"
                onClick={isRegisterMode ? () => alert("Registro...") : handleLogin}
              >
                {isRegisterMode ? 'Registrar' : 'Entrar'}
              </button>
              <button 
                className="flex-1 bg-[#e1e8ed] text-gray-700 font-bold py-3 rounded-xl hover:bg-white transition"
                onClick={() => setIsRegisterMode(!isRegisterMode)}
              >
                {isRegisterMode ? 'Login' : 'Registro'}
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // --- INTERFAZ TIPO IMAGEN 1 (WALMART STYLE) ---
  return (
    <div className="min-h-screen bg-white">
      {/* Header tipo Walmart */}
      <header className="bg-[#0071ce] text-white sticky top-0 z-50 shadow-md">
        <div className="max-w-7xl mx-auto px-4 py-3 flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-bold italic tracking-tighter">Walmart <span className="text-[#ffc220]">★</span></h1>
            <button className="hidden md:block bg-[#004f91] px-4 py-2 rounded-full text-sm font-bold border border-white/20">
              <i className="fas fa-th-large mr-2"></i> Departamentos
            </button>
          </div>

          <div className="flex-1 max-w-2xl relative">
            <input 
              type="text" 
              placeholder="¿Qué deseas buscar hoy?" 
              className="w-full py-2 px-4 pr-12 rounded-full text-gray-800 outline-none shadow-inner"
              value={busqueda}
              onChange={(e) => { setBusqueda(e.target.value); optimizadaBusqueda(e.target.value); }}
            />
            <button className="absolute right-2 top-1 bg-[#ffc220] text-gray-800 w-9 h-9 rounded-full flex items-center justify-center">
              <i className="fas fa-search"></i>
            </button>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden lg:block text-xs">
              <p>Ver tutorial</p>
              <p className="font-bold">Mi cuenta</p>
            </div>
            <button onClick={() => setIsLoggedIn(false)} className="bg-[#ffc220] text-gray-800 px-6 py-2 rounded-full font-bold text-sm shadow-md hover:bg-[#e5ae1d]">
              $0.00 <i className="fas fa-shopping-cart ml-2"></i>
            </button>
          </div>
        </div>

        {/* Barra de Categorías */}
        <div className="bg-[#0071ce] border-t border-white/10 hidden md:block">
            <div className="max-w-7xl mx-auto px-4 py-2 flex gap-8 text-sm font-medium overflow-x-auto whitespace-nowrap">
                <button onClick={() => setView('dashboard')} className={view === 'dashboard' ? 'border-b-2 border-white' : ''}>DASHBOARD</button>
                <button onClick={() => setView('productos')} className={view === 'productos' ? 'border-b-2 border-white' : ''}>INVENTARIO</button>
                <button>DESPENSA</button>
                <button>LÁCTEOS</button>
                <button>FRUTAS Y VERDURAS</button>
            </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {view === "dashboard" ? (
          <div className="space-y-6">
            <div className="bg-sky-50 p-6 rounded-lg border-l-4 border-[#0071ce]">
                <h2 className="text-2xl font-bold text-[#004f91]">Bienvenido al Gestor de Tienda</h2>
                <p className="text-gray-600 italic">"Walmart cuenta con venta de despensa, alimentos y más..."</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 border rounded-xl shadow-sm text-center">
                <p className="text-gray-500 uppercase text-xs font-bold tracking-widest">Productos</p>
                <p className="text-4xl font-black text-[#0071ce]">{stats.total_productos}</p>
              </div>
              <div className="bg-white p-6 border rounded-xl shadow-sm text-center">
                <p className="text-gray-500 uppercase text-xs font-bold tracking-widest">Bajo Stock</p>
                <p className="text-4xl font-black text-red-500">{stats.bajo_stock}</p>
              </div>
              <div className="bg-white p-6 border rounded-xl shadow-sm text-center">
                <p className="text-gray-500 uppercase text-xs font-bold tracking-widest">Valor Inventario</p>
                <p className="text-4xl font-black text-green-600">${stats.valor_inventario}</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="bg-white">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Control de Inventario</h2>
                <button 
                  onClick={() => setShowForm(!showForm)}
                  className="bg-[#0071ce] text-white px-6 py-2 rounded-full font-bold hover:bg-[#004f91] transition"
                >
                    {showForm ? 'Cerrar' : '+ Agregar Producto'}
                </button>
            </div>

            {showForm && (
              <div className="mb-8 p-6 bg-gray-50 rounded-2xl border border-dashed border-gray-300 grid grid-cols-1 md:grid-cols-4 gap-4">
                  <input className="p-3 border rounded-xl" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                  <input className="p-3 border rounded-xl" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                  <input className="p-3 border rounded-xl" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                  <button onClick={guardarProducto} className="bg-[#ffc220] text-gray-800 font-bold rounded-xl py-3 hover:brightness-110">GUARDAR PRODUCTO</button>
              </div>
            )}

            <div className="border rounded-2xl overflow-hidden shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-gray-100 text-gray-600 text-sm uppercase">
                      <tr>
                        <th className="p-4">Producto</th>
                        <th className="p-4">Existencia</th>
                        <th className="p-4">Precio Venta</th>
                        <th className="p-4 text-center">Acciones</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y">
                      {productos.map(p => (
                      <tr key={p.id} className="hover:bg-blue-50/50 transition">
                          <td className="p-4 font-bold text-[#004f91]">{p.nombre}</td>
                          <td className="p-4">
                            <span className={`px-3 py-1 rounded-full text-xs font-bold ${p.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                                {p.stock} pzas
                            </span>
                          </td>
                          <td className="p-4 font-mono font-bold">${p.precio_venta}</td>
                          <td className="p-4 text-center space-x-2">
                            <button className="text-blue-600 hover:scale-110 transition"><i className="fas fa-edit"></i></button>
                            <button className="text-red-500 hover:scale-110 transition"><i className="fas fa-trash"></i></button>
                          </td>
                      </tr>
                      ))}
                  </tbody>
                </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
